import { Injectable } from '@angular/core';
import { Observable } from 'rxjs';
import { map } from 'rxjs/operators';
import { ApiService } from './api.service';
import { PagedResult } from '../models/common.models';
import {
  AssignmentDetailDto, SubmissionDto,
  CreateAssignmentDto, SubmitAssignmentDto, GradeSubmissionDto
} from '../models/assignment.models';

@Injectable({ providedIn: 'root' })
export class AssignmentService {
  constructor(private api: ApiService) {}

  getById(id: number): Observable<AssignmentDetailDto> {
    return this.api.get<AssignmentDetailDto>(`assignments/${id}`);
  }

  create(dto: CreateAssignmentDto): Observable<AssignmentDetailDto> {
    return this.api.post<AssignmentDetailDto>('assignments', dto);
  }

  delete(id: number): Observable<void> {
    return this.api.delete(`assignments/${id}`);
  }

  submit(assignmentId: number, dto: SubmitAssignmentDto): Observable<SubmissionDto> {
    return this.api.post<SubmissionDto>(`assignments/${assignmentId}/submit`, dto);
  }

  grade(submissionId: number, dto: GradeSubmissionDto): Observable<SubmissionDto> {
    return this.api.post<SubmissionDto>(`assignments/submissions/${submissionId}/grade`, dto);
  }

  getPendingGrading(): Observable<PagedResult<SubmissionDto>> {
    return this.api.getPaged<SubmissionDto>('assignments/pending-grading');
  }

  getByCourse(courseId: number): Observable<AssignmentDetailDto[]> {
    return this.api.getPaged<AssignmentDetailDto>('assignments', { courseId }).pipe(map(r => r.items));
  }
}
